import React from 'react';
import { useNavigate, Link } from 'react-router-dom';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  return (
    <header style={{
      background: 'linear-gradient(135deg, #ffffff 0%, #f5f7fa 100%)',
      boxShadow: '0 2px 10px rgba(0, 0, 0, 0.07)',
      padding: '1.2rem 2.2rem',
      borderBottom: '1px solid rgba(0, 0, 0, 0.05)',
      fontFamily: 'Poppins, Inter, sans-serif',
      fontWeight: 500,
      letterSpacing: 0.1,
      zIndex: 100
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <Link to="/dashboard">
              <img 
                src="/Logo/spa" 
                alt="Loyalstring" 
                style={{ 
                  height: '48px',
                  marginRight: '30px'
                }} 
              />
            </Link>
            <nav className="d-flex align-items-center">
              <Link 
                to="/dashboard"
                style={{
                  textDecoration: 'none',
                  color: '#666',
                  fontSize: '0.95rem',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'rgba(84, 112, 255, 0.1)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.15)';
                  e.currentTarget.style.color = '#5470FF';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.1)';
                  e.currentTarget.style.color = '#666';
                }}
              >
                <i className="fas fa-home me-2" style={{ color: '#5470FF' }}></i>
                Home
              </Link>
              
              <Link 
                to="/rfid-integration"
                style={{
                  marginLeft: '24px',
                  textDecoration: 'none', 
                  color: '#666',
                  fontSize: '0.95rem',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'rgba(84, 112, 255, 0.1)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.15)';
                  e.currentTarget.style.color = '#5470FF';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.1)';
                  e.currentTarget.style.color = '#666';
                }}
              >
                <i className="fas fa-plug me-2" style={{ color: '#5470FF' }}></i>
                RFID Integration
              </Link>

              <Link 
                to="/inventory"
                style={{
                  marginLeft: '24px',
                  textDecoration: 'none', 
                  color: '#666',
                  fontSize: '0.95rem',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'rgba(84, 112, 255, 0.1)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.15)';
                  e.currentTarget.style.color = '#5470FF';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.1)';
                  e.currentTarget.style.color = '#666';
                }}
              >
                <i className="fas fa-box me-2" style={{ color: '#5470FF' }}></i>
                Inventory
              </Link>

              <Link 
                to="/upload-rfid"
                style={{
                  marginLeft: '24px',
                  textDecoration: 'none', 
                  color: '#666',
                  fontSize: '0.95rem',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'rgba(84, 112, 255, 0.1)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.15)';
                  e.currentTarget.style.color = '#5470FF';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'rgba(84, 112, 255, 0.1)';
                  e.currentTarget.style.color = '#666';
                }}
              >
                <i className="fas fa-upload me-2" style={{ color: '#5470FF' }}></i>
                Upload RFID Data
              </Link>
            </nav>
          </div>
          
          {userInfo && (
            <div className="d-flex align-items-center">
              <div style={{
                background: 'rgba(84, 112, 255, 0.1)',
                padding: '8px 16px',
                borderRadius: '20px',
                marginRight: '20px',
                display: 'flex',
                alignItems: 'center',
                fontFamily: 'Poppins, Inter, sans-serif',
                fontWeight: 600
              }}>
                <i className="fas fa-user-circle me-2" style={{ color: '#5470FF' }}></i>
                <span style={{ 
                  fontWeight: 600,
                  color: '#333',
                  marginRight: '12px',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontSize: '1.05rem'
                }}>
                  {userInfo.Username}
                </span>
                <span style={{
                  background: 'rgba(84, 112, 255, 0.2)',
                  padding: '4px 8px',
                  borderRadius: '12px',
                  fontSize: '0.85rem',
                  color: '#5470FF',
                  fontWeight: 500
                }}>
                  {userInfo.ClientCode}
                </span>
              </div>
              
              <button
                onClick={handleLogout}
                style={{
                  background: 'linear-gradient(45deg, #FF416C, #FF4B2B)',
                  color: 'white',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: '20px',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'all 0.3s',
                  boxShadow: '0 4px 15px rgba(255, 65, 108, 0.2)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600
                }}
                onMouseOver={e => {
                  e.currentTarget.style.transform = 'translateY(-2px)';
                  e.currentTarget.style.boxShadow = '0 6px 20px rgba(255, 65, 108, 0.3)';
                }}
                onMouseOut={e => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 4px 15px rgba(255, 65, 108, 0.2)';
                }}
              >
                <i className="fas fa-sign-out-alt me-2"></i>
                Logout
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;
